// MergePatch applies RFC 7396 JSON Merge Patch to original.
// Null values in patch remove keys, other values replace.
func MergePatch(original, patch map[string]interface{}) map[string]interface{} {
	if original == nil {
		original = make(map[string]interface{})
	}
	result := make(map[string]interface{})
	// Copy original
	for k, v := range original {
		result[k] = v
	}
	// Apply patch
	for k, v := range patch {
		if v == nil {
			delete(result, k)
		} else if patchMap, ok := v.(map[string]interface{}); ok {
			// Recursive merge for nested objects
			origMap, _ := result[k].(map[string]interface{})
			result[k] = MergePatch(origMap, patchMap)
		} else {
			result[k] = v
		}
	}
	return result
}
